Greedy insertion with best-fit selection using incremental cost evaluation across all existing assigns and a fallback empty assign creation if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestCostDelta := math.MaxFloat64
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		// Evaluate insertion into each existing non-empty assign
		for i := 0; i < dispatch.AssignsLen; i++ {
			prevCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					costDelta := newCost - prevCost
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = i
					}
				}
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].GenRoute()
			}
		}

		// Also consider inserting into a new empty assign if within bounds
		if dispatch.AssignsLen < MAXASSIGNS {
			i := dispatch.AssignsLen
			prevCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					costDelta := newCost - prevCost
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = i
					}
				}
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].GenRoute()
			}
		}

		// Perform the actual insertion at the chosen position
		inserted := false
		if bestAssignIdx != -1 {
			ok := dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				if dispatch.Assigns[bestAssignIdx].Cost >= 0 {
					if bestAssignIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen++
					}
					inserted = true
				} else {
					dispatch.Assigns[bestAssignIdx].RemoveShip(shipID)
					dispatch.Assigns[bestAssignIdx].GenRoute()
				}
			}
		}

		// Fallback: try every assign sequentially until success (including new empty ones)
		if !inserted {
			for i := 0; i <= dispatch.AssignsLen && i < MAXASSIGNS; i++ {
				ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						if i >= dispatch.AssignsLen {
							dispatch.AssignsLen++
						}
						inserted = true
						break
					} else {
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

